<?php
/**
 * AJAX handlers for onboarding
 */

if (!defined('ABSPATH')) {
    exit;
}

// Load build-time config (generated by Vite)
$proleadsai_build_config = dirname(__DIR__) . '/build-config.php';
if (file_exists($proleadsai_build_config)) {
    require_once $proleadsai_build_config;
}

/**
 * Get the base URL (without /api suffix)
 * Uses build-config.php generated by Vite, or falls back to production
 */
function proleadsai_get_base_url() {
    // Use build-time constant from Vite (includes/build-config.php)
    if (defined('PROLEADSAI_BASE_URL')) {
        return PROLEADSAI_BASE_URL;
    }
    
    // Fallback to production
    return 'https://app.proleadsai.com';
}

/**
 * Get the API URL (base URL + /api)
 */
function proleadsai_get_api_url() {
    return proleadsai_get_base_url() . '/api';
}

/**
 * Helper function to make API requests with proper SSL handling
 * Handles SSL compatibility issues with older PHP/OpenSSL versions
 */
function proleadsai_api_request($url, $args = array()) {
    $defaults = array(
        'timeout' => 30,
        'sslverify' => true,
        'headers' => array('Content-Type' => 'application/json'),
    );
    
    $args = wp_parse_args($args, $defaults);
    
    return wp_remote_request($url, $args);
}

/**
 * Verify nonce and capability for AJAX requests
 */
function proleadsai_verify_ajax_request() {
    // Check nonce from header or POST data
    $nonce = isset($_SERVER['HTTP_X_WP_NONCE']) ? sanitize_text_field(wp_unslash($_SERVER['HTTP_X_WP_NONCE'])) : '';
    if (empty($nonce)) {
        $json = file_get_contents('php://input');
        $data = json_decode($json, true);
        $nonce = $data['_wpnonce'] ?? '';
    }
    
    if (!wp_verify_nonce($nonce, 'wp_rest')) {
        wp_send_json_error(array('message' => 'Security check failed'), 403);
        exit;
    }
    
    // Check user capability
    if (!current_user_can('manage_options')) {
        wp_send_json_error(array('message' => 'Permission denied'), 403);
        exit;
    }
}

/**
 * Send verification email (OTP)
 */
function proleadsai_send_verification_email() {
    proleadsai_verify_ajax_request();
    
    $json = file_get_contents('php://input');
    $data = json_decode($json, true);
    
    $email = sanitize_email($data['email'] ?? '');
    
    if (empty($email)) {
        wp_send_json_error(array('message' => 'Email is required'));
        return;
    }
    
    $api_url = proleadsai_get_api_url();
    
    $response = proleadsai_api_request($api_url . '/wordpress/auth/register', array(
        'method' => 'POST',
        'body' => json_encode(array('email' => $email))
    ));
    
    if (is_wp_error($response)) {
        wp_send_json_error(array('message' => $response->get_error_message()));
        return;
    }
    
    $status_code = wp_remote_retrieve_response_code($response);
    $body = wp_remote_retrieve_body($response);
    $result = json_decode($body, true);
    
    if ($status_code >= 400) {
        wp_send_json_error(array('message' => $result['message'] ?? 'Failed to send verification email'));
        return;
    }
    
    wp_send_json_success($result);
}
add_action('wp_ajax_proleadsai_send_verification_email', 'proleadsai_send_verification_email');

