/**
 * Update organization settings
 */
function proleadsai_update_organization() {
    proleadsai_verify_ajax_request();
    
    $json = file_get_contents('php://input');
    $data = json_decode($json, true);
    
    $team_id = sanitize_text_field($data['team_id'] ?? '');
    $auth_token = sanitize_text_field($data['auth_token'] ?? '');
    
    if (empty($team_id) || empty($auth_token)) {
        wp_send_json_error(array('message' => 'Missing credentials'));
        return;
    }
    
    $api_url = proleadsai_get_api_url();
    
    $response = proleadsai_api_request($api_url . '/organization/' . $team_id . '/settings', array(
        'method' => 'PATCH',
        'headers' => array(
            'Content-Type' => 'application/json',
            'x-api-key' => $auth_token
        ),
        'body' => json_encode(array(
            'name' => sanitize_text_field($data['name'] ?? ''),
            'googleMapsApiKey' => sanitize_text_field($data['googleMapsApiKey'] ?? ''),
            'pricePerSq' => intval($data['pricePerSq'] ?? 750)
        ))
    ));
    
    if (is_wp_error($response)) {
        wp_send_json_error(array('message' => $response->get_error_message()));
        return;
    }
    
    $body = wp_remote_retrieve_body($response);
    $result = json_decode($body, true);
    
    wp_send_json_success($result);
}
add_action('wp_ajax_proleadsai_update_organization', 'proleadsai_update_organization');

/**
 * Validate Google Maps API Key
 * Tests Places Autocomplete and Solar API directly from WordPress server
 * This ensures the API key works with the domain restrictions set by the user
 */
function proleadsai_validate_api_key() {
    proleadsai_verify_ajax_request();
    
    $json = file_get_contents('php://input');
    $data = json_decode($json, true);
    
    $api_key = sanitize_text_field($data['apiKey'] ?? $data['placesApiKey'] ?? '');
    $wp_base_url = sanitize_text_field($data['wpBaseUrl'] ?? '');
    
    if (empty($api_key)) {
        wp_send_json_error(array('message' => 'API key is required'));
        return;
    }

    if (empty($wp_base_url)) {
        $wp_base_url = get_site_url();
    }

    $base_url = function_exists('proleadsai_get_base_url') ? proleadsai_get_base_url() : 'https://app.proleadsai.com';
    $endpoint = rtrim($base_url, '/') . '/api/wordpress/auth/validate-maps-key';

    $response = proleadsai_api_request($endpoint, array(
        'method' => 'POST',
        'headers' => array('Content-Type' => 'application/json'),
        'body' => wp_json_encode(array(
            'apiKey' => $api_key,
            'wpBaseUrl' => $wp_base_url,
        )),
        'timeout' => 20,
    ));

    if (is_wp_error($response)) {
        wp_send_json_error(array('message' => $response->get_error_message()));
        return;
    }

    $status_code = wp_remote_retrieve_response_code($response);
    $body = wp_remote_retrieve_body($response);
    $decoded = json_decode($body, true);

    if ($status_code >= 400) {
        wp_send_json_error(array('message' => $decoded['message'] ?? 'Failed to validate API key'));
        return;
    }

    $results = $decoded['results'] ?? array();

    // Determine overall success based on Places API validation
    $success = true;
    foreach ($results as $host => $checks) {
        if (empty($checks['placesApi']['valid'])) {
            $success = false;
            break;
        }
    }

    wp_send_json_success(array(
        'success' => $success,
        'results' => $results,
    ));
}
add_action('wp_ajax_proleadsai_validate_api_key', 'proleadsai_validate_api_key');

/**
 * Validate Google Solar API Key via backend
 * This tests the Solar API server-side since it doesn't have referrer restrictions
 */
function proleadsai_validate_solar_api() {
    proleadsai_verify_ajax_request();
    
    $json = file_get_contents('php://input');
    $data = json_decode($json, true);
    
    $api_key = sanitize_text_field($data['apiKey'] ?? '');
    
    if (empty($api_key)) {
        wp_send_json_error(array('message' => 'API key is required'));
        return;
    }

    $base_url = function_exists('proleadsai_get_base_url') ? proleadsai_get_base_url() : 'https://app.proleadsai.com';
    $endpoint = rtrim($base_url, '/') . '/api/wordpress/auth/validate-maps-key';

    $response = proleadsai_api_request($endpoint, array(
        'method' => 'POST',
        'headers' => array('Content-Type' => 'application/json'),
        'body' => wp_json_encode(array(
            'apiKey' => $api_key,
        )),
        'timeout' => 20,
    ));

    if (is_wp_error($response)) {
        wp_send_json_error(array('message' => $response->get_error_message()));
        return;
    }

    $status_code = wp_remote_retrieve_response_code($response);
    $body = wp_remote_retrieve_body($response);
    $decoded = json_decode($body, true);

    if ($status_code >= 400) {
        wp_send_json_error(array('message' => $decoded['message'] ?? 'Failed to validate Solar API'));
        return;
    }

    wp_send_json_success(array(
        'success' => $decoded['success'] ?? false,
        'solarApi' => $decoded['solarApi'] ?? array('valid' => false, 'message' => 'Unknown error'),
    ));
}
add_action('wp_ajax_proleadsai_validate_solar_api', 'proleadsai_validate_solar_api');

