/**
 * Proxy: Get settings from Better Auth API
 */
function proleadsai_proxy_get_settings() {
    proleadsai_verify_ajax_request();
    
    $settings = get_option('proleadsai_onboarding', array());
    $auth_token = $settings['auth_token'] ?? '';
    
    if (empty($auth_token)) {
        wp_send_json_error(array('message' => 'Not authenticated'));
        return;
    }
    
    $api_url = proleadsai_get_api_url();
    
    $response = proleadsai_api_request($api_url . '/wordpress/settings', array(
        'method' => 'GET',
        'headers' => array(
            'Content-Type' => 'application/json',
            'x-api-key' => $auth_token,
            'Accept' => 'application/json'
        )
    ));
    
    if (is_wp_error($response)) {
        wp_send_json_error(array('message' => $response->get_error_message()));
        return;
    }
    
    $status_code = wp_remote_retrieve_response_code($response);
    $body = wp_remote_retrieve_body($response);
    $data = json_decode($body, true);
    
    if ($status_code >= 400) {
        wp_send_json_error(array('message' => $data['message'] ?? 'Failed to fetch settings'));
        return;
    }
    
    // Sync API data back to WordPress
    if ($data) {
        $updates = array();
        if (!empty($data['name'])) $updates['business'] = $data['name'];
        if (!empty($data['email'])) $updates['email'] = $data['email'];
        if (isset($data['googleMapsApiKey'])) $updates['google_maps_api_key'] = $data['googleMapsApiKey'];
        if (isset($data['googleSolarApiKey'])) $updates['google_solar_api_key'] = $data['googleSolarApiKey'];
        if (isset($data['pricePerSq'])) $updates['price_per_sq'] = strval($data['pricePerSq']);
        if (!empty($data['timezone'])) $updates['timezone'] = $data['timezone'];
        if (!empty($data['id'])) $updates['team_id'] = $data['id'];
        
        if (!empty($updates)) {
            $current = get_option('proleadsai_onboarding', array());
            update_option('proleadsai_onboarding', array_merge($current, $updates));
        }
    }
    
    wp_send_json_success($data);
}
add_action('wp_ajax_proleadsai_proxy_get_settings', 'proleadsai_proxy_get_settings');

/**
 * Proxy: Get dashboard data from Better Auth API
 */
function proleadsai_proxy_get_dashboard() {
    proleadsai_verify_ajax_request();
    
    $settings = get_option('proleadsai_onboarding', array());
    $auth_token = $settings['auth_token'] ?? '';
    
    if (empty($auth_token)) {
        wp_send_json_error(array('message' => 'Not authenticated'));
        return;
    }
    
    $api_url = proleadsai_get_api_url();
    
    // Verify nonce for GET parameter processing (check header first, then request data)
    $nonce = '';
    if (isset($_SERVER['HTTP_X_WP_NONCE'])) {
        $nonce = sanitize_text_field(wp_unslash($_SERVER['HTTP_X_WP_NONCE']));
    } elseif (isset($_REQUEST['_wpnonce'])) {
        $nonce = sanitize_text_field(wp_unslash($_REQUEST['_wpnonce']));
    }
    
    if (empty($nonce) || !wp_verify_nonce($nonce, 'wp_rest')) {
        wp_send_json_error(array('message' => 'Security check failed'), 403);
        return;
    }
    
    // Forward date range params if provided
    $query_params = array();
    if (!empty($_GET['startDate'])) {
        $query_params['startDate'] = sanitize_text_field(wp_unslash($_GET['startDate']));
    }
    if (!empty($_GET['endDate'])) {
        $query_params['endDate'] = sanitize_text_field(wp_unslash($_GET['endDate']));
    }
    
    $url = $api_url . '/wordpress/dashboard';
    if (!empty($query_params)) {
        $url .= '?' . http_build_query($query_params);
    }
    
    $response = proleadsai_api_request($url, array(
        'method' => 'GET',
        'headers' => array(
            'Content-Type' => 'application/json',
            'x-api-key' => $auth_token,
            'Accept' => 'application/json'
        )
    ));
    
    if (is_wp_error($response)) {
        wp_send_json_error(array('message' => $response->get_error_message()));
        return;
    }
    
    $status_code = wp_remote_retrieve_response_code($response);
    $body = wp_remote_retrieve_body($response);
    $data = json_decode($body, true);
    
    if ($status_code >= 400) {
        wp_send_json_error(array('message' => $data['message'] ?? 'Failed to fetch dashboard data'));
        return;
    }
    
    wp_send_json_success($data);
}
add_action('wp_ajax_proleadsai_proxy_get_dashboard', 'proleadsai_proxy_get_dashboard');

/**
 * Proxy: Save settings to Better Auth API
 */
function proleadsai_proxy_save_settings() {
    proleadsai_verify_ajax_request();
    
    $settings = get_option('proleadsai_onboarding', array());
    $auth_token = $settings['auth_token'] ?? '';
    
    if (empty($auth_token)) {
        wp_send_json_error(array('message' => 'Not authenticated'));
        return;
    }
    
    $json = file_get_contents('php://input');
    $data = json_decode($json, true);
    
    $api_url = proleadsai_get_api_url();
    
    $body = array();
    if (isset($data['name'])) $body['name'] = sanitize_text_field($data['name']);
    if (isset($data['googleMapsApiKey'])) $body['googleMapsApiKey'] = sanitize_text_field($data['googleMapsApiKey']);
    if (isset($data['googleSolarApiKey'])) $body['googleSolarApiKey'] = sanitize_text_field($data['googleSolarApiKey']);
    if (isset($data['pricePerSq'])) $body['pricePerSq'] = intval($data['pricePerSq']);
    if (isset($data['timezone'])) $body['timezone'] = sanitize_text_field($data['timezone']);
    
    $response = proleadsai_api_request($api_url . '/wordpress/settings', array(
        'method' => 'POST',
        'headers' => array(
            'Content-Type' => 'application/json',
            'x-api-key' => $auth_token,
            'Accept' => 'application/json'
        ),
        'body' => json_encode($body)
    ));
    
    if (is_wp_error($response)) {
        wp_send_json_error(array('message' => $response->get_error_message()));
        return;
    }
    
    $status_code = wp_remote_retrieve_response_code($response);
    $response_body = wp_remote_retrieve_body($response);
    $result = json_decode($response_body, true);
    
    if ($status_code >= 400) {
        wp_send_json_error(array('message' => $result['message'] ?? 'Failed to save settings'));
        return;
    }
    
    // Sync to WordPress after successful API save
    $updates = array();
    if (isset($data['name'])) $updates['business'] = $data['name'];
    if (isset($data['googleMapsApiKey'])) $updates['google_maps_api_key'] = $data['googleMapsApiKey'];
    if (isset($data['googleSolarApiKey'])) $updates['google_solar_api_key'] = $data['googleSolarApiKey'];
    if (isset($data['pricePerSq'])) $updates['price_per_sq'] = strval($data['pricePerSq']);
    if (isset($data['timezone'])) $updates['timezone'] = $data['timezone'];
    
    if (!empty($updates)) {
        $current = get_option('proleadsai_onboarding', array());
        update_option('proleadsai_onboarding', array_merge($current, $updates));
    }
    
    wp_send_json_success($result);
}
add_action('wp_ajax_proleadsai_proxy_save_settings', 'proleadsai_proxy_save_settings');
